     private string ConvertMillions(long number)
     {
         if (number / 1_000_000 == 1)
         {
             if (number % 1_000_000 == 0)
             {
                 return "ένα εκατομμύριο";
             }

             // Anti-pattern: .ToLower() inside interpolation
