         var result = $"{ConvertImpl(number / 1_000_000, false)} εκατομμύρια";

         if (number % 1_000_000 != 0)
         {
             // Anti-pattern: result += with .ToLower() in interpolation
             result += $" {ConvertImpl(number % 1_000_000, false).ToLower()}";
         }

         return result;
