     /// Converts a number in the billions range to Greek words.
     /// </summary>
     private string ConvertBillions(long number)
     {
         if (number / 1_000_000_000 == 1)
         {
             if (number % 1_000_000_000 == 0)
             {
                 return "ένα δισεκατομμύριο";
